 1	import * as React from 'react';
 2	import {
 3	  Bullseye,
 4	  EmptyState,
 5	  EmptyStateBody,
 6	  EmptyStateVariant,
 7	  Title,
 8	} from '@patternfly/react-core';
 9	import { Table, Thead, Tbody, Th, Td, Tr } from '@patternfly/react-table';
10	import { useTranslation } from 'react-i18next';
11	import { ComputedStatus, TektonResultsRun } from '../../../types';
12	import { handleURLs } from '../../utils/render-utils';
13	
14	export interface ResultsListProps {
15	  results: TektonResultsRun[];
16	  resourceName: string;
17	  status: string;
18	}
19	
20	const ResultsList: React.FC<ResultsListProps> = ({
21	  results,
22	  resourceName,
23	  status,
24	}) => {
25	  const { t } = useTranslation('plugin__pipelines-console-plugin');
26	  if (!results.length) return null;
27	
28	  return (
29	    <>
30	      <Title headingLevel="h2">
31	        {t('{{resourceName}} results', { resourceName })}
32	      </Title>
33	      {status !== ComputedStatus.Failed ? (
34	        <Table
35	          aria-label={t('{{resourceName}} results', {
36	            resourceName,
37	          })}
38	          data-codemods="true"
39	        >
40	          <Thead>
41	            <Tr>
42	              <Th>{t('Name')}</Th>
43	              <Th>{t('Value')}</Th>
44	            </Tr>
45	          </Thead>
46	          <Tbody>
47	            {results.map(({ name, value }) => (
48	              <Tr key={`row-${name}`}>
49	                <Td>{name}</Td>
50	                <Td>{handleURLs(value)}</Td>
51	              </Tr>
52	            ))}
53	          </Tbody>
54	        </Table>
55	      ) : (
56	        <Bullseye>
57	          <EmptyState variant={EmptyStateVariant.full}>
58	            <EmptyStateBody>
59	              {t('No {{resourceName}} results available due to failure', {
60	                resourceName,
61	              })}
62	            </EmptyStateBody>
63	          </EmptyState>
64	        </Bullseye>
65	      )}
66	    </>
67	  );
68	};
69	
70	export default ResultsList;

